import React from "react";
import "../styles/Header.css";

export default function Header() {
  return (
    <div id="header">
      <div>
        <p className="header-txt">
          From Complexity to Clarity:
          <br />
          <span className="header-txt-bold">
            Simplify Your
            <br />
            Society Management Process
          </span>
        </p>
      </div>
    </div>
  );
}
